"use strict";(globalThis.webpackChunktanyaacjain_github_io=globalThis.webpackChunktanyaacjain_github_io||[]).push([[259],{4989:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/aaa/about","metadata":{"permalink":"/tech/aaa/about","source":"@site/work/aaa/about.md","title":"aaa","description":"First GenAI hire brought in to architect and scale the enterprise GenAI program, partnered with product leadership to launch 7 product lines and deliver $4.8M in annual operational savings. Architected & scaled the flagship roadside assistance platform from 0 to 1, serving 60K+ DAUs, and driving a 44% increase in accuracy across AI-powered interactions.","date":"2026-01-15T00:00:00.000Z","tags":[{"inline":false,"label":"Gen AI at AAA","permalink":"/tech/tags/aaa","description":"AAA"}],"readingTime":0.27,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"aaa","tags":["aaa"],"authors":"tanya","date":"2026-01-15T00:00:00.000Z","type":"about","remarks":[{"quote":"You are a true engineer.","name":"Charlie Florez Paz"},{"quote":"You are a hard working person. I deeply admire your work-ethic.","name":"Mansu Rousta"},{"quote":"In my last ~10 years of career, I haven\'t seen anyone make dashboards as beautiful as these.","name":"Vernes Okanovich"},{"quote":"Just wanted to say thanks for the awesome work you did with us. ","name":"Steven To"}]},"unlisted":false,"nextItem":{"title":"The Invisible Integration Architecture","permalink":"/tech/aaa/invisible-integration-architecture"}},"content":"First GenAI hire brought in to architect and scale the enterprise GenAI program, partnered with product leadership to launch 7 product lines and deliver $4.8M in annual operational savings. Architected & scaled the flagship roadside assistance platform from 0 to 1, serving 60K+ DAUs, and driving a 44% increase in accuracy across AI-powered interactions."},{"id":"/aaa/invisible-integration-architecture","metadata":{"permalink":"/tech/aaa/invisible-integration-architecture","source":"@site/work/aaa/invisible-integration-architecture.md","title":"The Invisible Integration Architecture","description":"When most developers see tickets on an agile board, they see tasks. I see leverage, often starting from point -1.","date":"2025-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Gen AI at AAA","permalink":"/tech/tags/aaa","description":"AAA"}],"readingTime":2.855,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"The Invisible Integration Architecture","tags":["aaa"],"authors":"tanya","date":"2025-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"aaa","permalink":"/tech/aaa/about"},"nextItem":{"title":"Essentia Softserv LLP","permalink":"/tech/other-engagements/essentia"}},"content":"When most developers see tickets on an agile board, they see tasks. I see leverage, often starting from point -1.\\n\\nOur company had dozens of digital properties: membership portals, insurance dashboards, travel booking engines, branch locators. Each operated as its own kingdom: different stacks, teams, release cycles, and definitions of \u201curgent.\\n\\nEvery new capability required negotiating entry into each one. This is the kind of friction that masquerades as process in high-bureaucracy environments: discovery calls, integration debates, version mismatches, bandwidth constraints.\\n\\nA simple feature, like a universal point of ingestion to our generative AI roadside assistant, turned into months of coordination. One property would launch. The rest would wait.\\n\\nI realized we were building a product that required adoption.\\n\\n**The problem was territorial.** \\n\\n## The Architecture of a Parasite\\n\\nI built the platform to behave like a parasite. Without asking for permission or negotiating entry, it attaches itself where traffic already exists and begins operating within the host, without requiring the host to change.\\n\\nTechnically, this meant a single script that:\\n- initializes its own DOM root if none exists\\n- detects the environment via domain/runtime signals\\n- routes to the correct backend without configuration\\n- operates independently of the host\u2019s stack or release cycle\\n\\nHandling session context across properties without direct integration required reconstructing user state from fragmented signals\u2014cookies, local storage, URL parameters\u2014and resolving them via backend identity mapping, all without relying on host-provided authentication hooks.\\n\\n### The Trade-offs That Made It Viable\\n\\nThis model prioritizes survival and sacrifices flexibility.\\n- No per-team customization surface to slow decisions.\\n- Limited visibility into internals. (UI, state, and logic were self-contained). \\n- Reduced control for host teams (environment inference via domain-based routing)\\n\\nIt also required strong guardrails to avoid interfering with host behavior.\\n\\nBut in early-stage systems\u2014especially in uncertain domains like GenAI\u2014distribution is the primary constraint. Removing friction mattered more than enabling control.\\n\\nThis reduced integration from a multi-week process to a ~30-second decision.\\n\\n## The Outcome Economics\\n\\nOver the next six months, the assistant appeared on over most properties. \\n\\nThere were no integration meetings, no onboarding docs, and almost no support requests. Teams adopted it independently because the cost to try was negligible and rollback was trivial.\\n\\n*\\"Add this script tag.\\"* <br />\\n*\\"That\'s it?\\"* <br />\\n*\\"That\'s it.\\"*\\n\\nWhat normally takes weeks of coordination became a same-day decision. Adoption worked because the value was immediately visible to end-users.\\n\\n## The Hidden Complexity\\n\\nThis simplicity was deliberate. Descoping became the core design tool. Every configuration option, like theming or customization, was a potential bottleneck disguised as flexibility. So it was removed.\\n\\nAll updates shipped centrally and became instantly available everywhere, without requiring any action from host teams.\\n\\nThe system knew how to find what it needed. The host didn\u2019t need to know anything.\\n\\n## The Lesson\\n\\nA platform requires upfront investment but compounds in value through adoption. Its scalability is determined by how easily it propagates.\\n\\nMost platforms behave like guests: waiting to be invited, configured, and maintained. They fail when they require effort to adopt.\\n\\nThis one behaved differently. It attached itself, adapted quietly, and delivered value unobtrusively.\\n\\n## Conclusive Thought\\nIf you want something to spread across an organization, don\u2019t optimize for configurability. Optimize for inevitability.\\n\\nThe most effective systems don\u2019t demand adoption. They make it unavoidable.\\n\\nThat\u2019s the kind of leverage I aim for, that is, build once, and remove the need for others to build at all."},{"id":"/other-engagements/essentia","metadata":{"permalink":"/tech/other-engagements/essentia","source":"@site/work/other-engagements/essentia.mdx","title":"Essentia Softserv LLP","description":"About the organisation","date":"2024-11-11T00:00:00.000Z","tags":[{"inline":false,"label":"Other engagements","permalink":"/tech/tags/other-engagements"}],"readingTime":1.06,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Essentia Softserv LLP","tags":["other-engagements"],"authors":"tanya","date":"2024-11-11T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"The Invisible Integration Architecture","permalink":"/tech/aaa/invisible-integration-architecture"},"nextItem":{"title":"Prismberry","permalink":"/tech/other-engagements/prismberry"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n#### About the organisation\\n\\n<OrganisationBlock \\n    name=\\"Essentia.dev\\"\\n    logoLight=\\"https://essentia.dev/images/logo.svg\\"\\n    logoDark=\\"\\"\\n    description=\\"[Essentia.dev](https://essentia.dev/) is an IT software solution provider based in Delhi, India.\\"\\n    socials={[\\n        { name: \'Website\', link: \'https://essentia.dev/\' },\\n        { name: \'LinkedIn\', link: \'https://www.linkedin.com/company/essentia-dev/about/\' },\\n    ]}\\n/>\\n\\n#### The work\\n\\n**The Challenge**: \\n\\nEssentia Softserv faced challenges with project timelines and system inefficiencies \\nthat affected client satisfaction and operational costs.\\n\\n**My Contributions**:\\n\\n- Spearheaded the integration of automation and agile practices to streamline development \\nprocesses, significantly reducing bottlenecks.\\n- Engineered and implemented robust database architectures across diverse tools, and developed \\nfrom scratch a comprehensive payment system to boost transaction success rates.\\n- Took up the responsibilities of a developer relations manager, liaising directly with clients \\nto tailor solutions to their needs, and guided cross-functional teams by instilling best practices.\\n- Actively represented the company at major industry conferences across India, enhancing our \\ncorporate profile and engagement with the tech community.\\n\\n**The Results**: \\n- Delivered a project that saved over $20,000, an amount significant enough to cover multiple \\ndevelopers\u2019 salaries for three months in India - cut project timelines by 40%, and lifted client \\nsatisfaction by 67%.\\n- Mentored a team of 20 trainees, improving our task completion rate by 10%, which underscored \\nmy dedication to team development and project excellence."},{"id":"/other-engagements/prismberry","metadata":{"permalink":"/tech/other-engagements/prismberry","source":"@site/work/other-engagements/prismberry.mdx","title":"Prismberry","description":"About the organisation","date":"2024-11-11T00:00:00.000Z","tags":[{"inline":false,"label":"Other engagements","permalink":"/tech/tags/other-engagements"}],"readingTime":1.11,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Prismberry","tags":["other-engagements"],"authors":"tanya","date":"2024-11-11T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"Essentia Softserv LLP","permalink":"/tech/other-engagements/essentia"},"nextItem":{"title":"RISC-V assembly interpreter, compilers, emulator and processor","permalink":"/tech/explorations/riscv/riscv"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n#### About the organisation\\n\\n<OrganisationBlock \\n    name=\\"Prismberry\\"\\n    logoLight=\\"https://prismberry.com/wp-content/smush-webp/2024/04/prismberry.png.webp\\"\\n    logoDark=\\"https://prismberry.com/wp-content/smush-webp/2024/04/prismberry.png.webp\\"\\n    description=\\"[Prismberry](https://prismberry.com/) is a consultancy service provider in software design and development focused on Artificial Intelligence, Product Engineering, Cloud Technologies, Data Analytics, Mobile Application, Automation, DevOps etc.\\"\\n    socials={[\\n        { name: \'Website\', link: \'https://prismberry.com/\' },\\n        { name: \'LinkedIn\', link: \'https://www.linkedin.com/company/prismberry-technologies\' },\\n    ]}\\n/>\\n\\n#### The work\\n\\n**The Objective**: \\n\\nEnsuring all teams across the company produce\\nhigh-quality deliverables for our clients, notably Flipkart.\\nI was responsible for the entire software development lifecycle, from requirements gathering\\nto deployment. \\n\\n**My Role**: \\n\\nI spearheaded an overhaul of the NLP systems and backend processes, \\nintegrating cutting-edge BERT models and optimizing SQL queries. My initial \\nproject involved training Transformer models from scratch on a custom language dataset, \\nand to deploy them on a production server. Later on, I worked on various products that drove \\n\\n**The Impact**: \\n\\nMy efforts significantly enhanced the reliability of our software, \\nimproving overall customer satisfaction and streamlining operations. \\nThese efforts include:\\n\\n- Increased NLP accuracy by 20% with new language BERT models on RTX 3080Ti GPUs.\\n- Boosted user engagement 25% by CNN based audio feature analysis and revamping e-commerce backend with Stripe & audio processing. \\n- Cut SQL query time 93%, from 15s to less than 1s, optimizing site performance.\\n- Enhanced software reliability 15% via test-driven development and code maintenance."},{"id":"/explorations/riscv/riscv","metadata":{"permalink":"/tech/explorations/riscv/riscv","source":"@site/work/explorations/riscv/riscv.md","title":"RISC-V assembly interpreter, compilers, emulator and processor","description":"","date":"2024-11-11T00:00:00.000Z","tags":[{"inline":false,"label":"Explorations","permalink":"/tech/tags/explorations"}],"readingTime":0,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"RISC-V assembly interpreter, compilers, emulator and processor","tags":["explorations"],"authors":"tanya","date":"2024-11-11T00:00:00.000Z","type":"project","cover_image":"/img/work/riscv.jpeg"},"unlisted":false,"prevItem":{"title":"Prismberry","permalink":"/tech/other-engagements/prismberry"},"nextItem":{"title":"Providing Aid to Local Communities With Technology","permalink":"/tech/local-community-support/about"}},"content":""},{"id":"/local-community-support/about","metadata":{"permalink":"/tech/local-community-support/about","source":"@site/work/local-community-support/about.mdx","title":"Providing Aid to Local Communities With Technology","description":"These are projects where technology meets human necessity, and where the measure of success is its endurance after I step away. They are expressions of a single approach: identify a gap, build systems that empower, and design for the work to outlast me.","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":0.215,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Providing Aid to Local Communities With Technology","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"about"},"unlisted":false,"prevItem":{"title":"RISC-V assembly interpreter, compilers, emulator and processor","permalink":"/tech/explorations/riscv/riscv"},"nextItem":{"title":"Digital Literacy - Extending Access Locally","permalink":"/tech/local-community-support/digital-literacy"}},"content":"These are projects where technology meets human necessity, and where the measure of success is its endurance after I step away. They are expressions of a single approach: identify a gap, build systems that empower, and design for the work to outlast me."},{"id":"/local-community-support/digital-literacy","metadata":{"permalink":"/tech/local-community-support/digital-literacy","source":"@site/work/local-community-support/digital-literacy.md","title":"Digital Literacy - Extending Access Locally","description":"Technology access remains unevenly distributed. So, I\u2019ve made it a personal commitment to help correct that imbalance\u2014teaching the children of household staff, volunteering with NGOs, and ensuring that the communities adjacent to my own are not left behind as the world digitizes.","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":0.3,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Digital Literacy - Extending Access Locally","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"Providing Aid to Local Communities With Technology","permalink":"/tech/local-community-support/about"},"nextItem":{"title":"Lowering Barriers to Access Eye Assessment","permalink":"/tech/local-community-support/eye-assessment"}},"content":"Technology access remains unevenly distributed. So, I\u2019ve made it a personal commitment to help correct that imbalance\u2014teaching the children of household staff, volunteering with NGOs, and ensuring that the communities adjacent to my own are not left behind as the world digitizes.\\n\\nNo formal program governs this work. It flows from a conviction that access, once earned, must be extended."},{"id":"/local-community-support/eye-assessment","metadata":{"permalink":"/tech/local-community-support/eye-assessment","source":"@site/work/local-community-support/eye-assessment.md","title":"Lowering Barriers to Access Eye Assessment","description":"At [CCFIS], I investigated whether mobile-optimized versions of eye and ear charts could increase engagement with preliminary vision and hearing assessments. This project stemmed from the question, if people could be met where they already reside,on their devices, to lower barriers to basic healthcare access?","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":0.39,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Lowering Barriers to Access Eye Assessment","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"Digital Literacy - Extending Access Locally","permalink":"/tech/local-community-support/digital-literacy"},"nextItem":{"title":"Sustainable Infrastructure Built with Community Ownership","permalink":"/tech/local-community-support/jhajhar"}},"content":"At [CCFIS], I investigated whether mobile-optimized versions of eye and ear charts could increase engagement with preliminary vision and hearing assessments. This project stemmed from the question, if people could be met where they already reside,on their devices, to lower barriers to basic healthcare access?\\n\\nWith this we meant accessibility is seldom merely a matter of cost. It demands meeting individuals in their existing contexts, with tools that integrate into their lives rather than disrupting them.\\n\\n[CCFIS]: https://www.ccfis.net"},{"id":"/local-community-support/jhajhar","metadata":{"permalink":"/tech/local-community-support/jhajhar","source":"@site/work/local-community-support/jhajhar.md","title":"Sustainable Infrastructure Built with Community Ownership","description":"When I encountered an infrastructure initiative in Jhajar district in Haryana, I recognized a familiar challenge. Villages needed inexpensive clean water and reliable energy. I spearheaded a project introducing water filtration and biogas power, but the deeper investment was in training. We focused on women homemakers, equipping them to operate and maintain the systems independently. The goal was not just cleaner water or renewable energy but a cascade: employment, self-sufficiency, and the confidence that emerges when a community controls its own infrastructure.","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":0.565,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Sustainable Infrastructure Built with Community Ownership","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"Lowering Barriers to Access Eye Assessment","permalink":"/tech/local-community-support/eye-assessment"},"nextItem":{"title":"Mentoring","permalink":"/tech/local-community-support/mentorships"}},"content":"When I encountered an infrastructure initiative in Jhajar district in Haryana, I recognized a familiar challenge. Villages needed inexpensive clean water and reliable energy. I spearheaded a project introducing water filtration and biogas power, but the deeper investment was in training. We focused on women homemakers, equipping them to operate and maintain the systems independently. The goal was not just cleaner water or renewable energy but a cascade: employment, self-sufficiency, and the confidence that emerges when a community controls its own infrastructure.\\n\\nThis work was selected as a finalist for IIIT-Delhi\u2019s \u201cBuilding Better Villages\u201d tech event. The recognition was welcome, but the enduring outcome is the community\u2019s continued stewardship for their own resources."},{"id":"/local-community-support/mentorships","metadata":{"permalink":"/tech/local-community-support/mentorships","source":"@site/work/local-community-support/mentorships.mdx","title":"Mentoring","description":"Mentoring is the structured transfer of practical wisdom and experience to foster development.","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":2.465,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Mentoring","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/girl-tech-power.JPG"},"unlisted":false,"prevItem":{"title":"Sustainable Infrastructure Built with Community Ownership","permalink":"/tech/local-community-support/jhajhar"},"nextItem":{"title":"CHYN - Revolutionizing Curated Travel with Cloud Computing","permalink":"/tech/explorations/chyn/chyn"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\nMentoring is the structured transfer of practical wisdom and experience to foster development.\\n\\n## AI Hackathon @ Berkeley\\n\\n#### About the initiative\\n\\n<OrganisationBlock \\n    name=\\"Cal Hacks @ Berkeley\\"\\n    logoLight=\\"https://ai.hackberkeley.org/_next/static/media/logo.de9dbd92.png\\"\\n    logoDark=\\"https://ai.hackberkeley.org/_next/static/media/logo.de9dbd92.png\\"\\n    description=\\"[Hackathons @ Berkeley](https://hackberkeley.org/) is a non-profit organization responsible for Cal Hacks, the world\'s largest collegiate hackathon which annually convenes innovators to explore technological boundaries.\\"\\n    socials={[\\n        { name: \'Website\', link: \'https://hackberkeley.org/\' },\\n        { name: \'Twitter\', link: \'https://twitter.com/CalHacks\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nAs a mentor at the AI Hackathon, I provided technical guidance and strategic feedback to competing teams, helping them refine their concepts and implement functional solutions within the event timeline.\\n\\n## Girl Tech Power \\n\\n#### About the initiative\\n\\n<OrganisationBlock \\n    name=\\"Girl Tech Power\\"\\n    logoLight=\\"https://pbs.twimg.com/profile_images/629735945139458048/b3AJOa5H_400x400.png\\"\\n    logoDark=\\"https://pbs.twimg.com/profile_images/629735945139458048/b3AJOa5H_400x400.png\\"\\n    description=\\"[Girl Tech Power](https://girltechpower.cs.usfca.edu/) is a summer code camp at the University of San Francisco designed to empower middle and high school girls to join the tech industry. Directed by Professor Alark Joshi and funded by Craig Newmark Philanthropies, the program concludes with a visit to a Bay Area tech company, where participants meet female engineers and present their final projects.\\"\\n    socials={[\\n        { name: \'Website\', link: \'https://girltechpower.cs.usfca.edu/\' },\\n        { name: \'Twitter\', link: \'https://x.com/girltechpower\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nAs a Girl Tech Power leader, I directed initiatives to teach middle and high school girls foundational Python coding, with a final project of building a functional game. To build community, each class concluded with Disney trivia. Participant feedback highlighted the supportive environment and the valuable technical skills acquired.\\n\\n<div className=\\"img-tb\\"> \\n| ![GTP 1](./girl_tech_power/1.JPG) | ![GTP 2](./girl_tech_power/2.JPG) | \\n|-|-|\\n| ![GTP 3](./girl_tech_power/3.JPG) | ![GTP 4](./girl_tech_power/4.JPG) |\\n\\n</div>\\n\\n\\n## Exercism\\n\\n#### About the organisation\\n\\n<OrganisationBlock \\n    name=\\"Exercism\\"\\n    logoLight=\\"https://assets.exercism.org/assets/icons/exercism-with-logo-black-12752bd7fcf6862ba8ad7a2b75e21a9b2409d7fd.svg\\"\\n    logoDark=\\"\\"\\n    description=\\"[Exercism](https://exercism.org/) is an online, open-source, free coding platform designed to help enhance coding skills through practice and mentorship on 70 programming languages and 5989 coding exercises. \\n    \\\\\\n    7.3K stars. 4.9K followers.\\"\\n    socials={[\\n        { name: \'GitHub\', link: \'https://github.com/exercism\' },\\n        { name: \'Website\', link: \'https://exercism.org/\' },\\n        { name: \'Twitter\', link: \'https://twitter.com/exercism_io\' },\\n        { name: \'Wiki\', link: \'https://en.wikipedia.org/wiki/Exercism\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nAs a mentor, I provided feedback and answered questions to help students improve their coding skills in Python and JavaScript, and learn new programming concepts.\\n\\n## ALiAS - Amity Linux Assistance Sapience\\n\\n#### About the organisation\\n\\n<OrganisationBlock \\n    name=\\"ALiAS\\"\\n    logoLight=\\"https://avatars.githubusercontent.com/u/20925586?s=280&v=4\\"\\n    logoDark=\\"https://avatars.githubusercontent.com/u/20925586?s=280&v=4\\"\\n    description=\\"[ALiAS](https://asetalias.in/) is a student-led organization cum tech community that fosters open-source culture, the use of Linux and the culture of hacking and sharing.\\"\\n    socials={[\\n        { name: \'GitHub\', link: \'https://github.com/asetalias\' },\\n        { name: \'Website\', link: \'https://asetalias.in/\' },\\n        { name: \'LinkTree\', link: \'https://linktr.ee/asetalias\' },\\n        { name: \'Twitter\', link: \'https://twitter.com/asetalias\' },\\n        { name: \'LinkedIn\', link: \'https://www.linkedin.com/company/asetalias/\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nAs President and a founding member, I guided newcomers through the contribution process, organized weekly meetings, led technical sessions, and established study groups. I also founded the \'Women in Tech\' initiative, organizing workshops and events to promote greater participation in the industry.\\n\\n<div className=\\"img-tb\\">\\n| ![ALiAS 1](./asetalias/02212017_1.jpeg) | ![ALiAS 2](./asetalias/03082017_1.jpeg) |\\n|-|-|\\n</div>\\n\\n:::note[[Read more about my journey with ALiAS](../../writings/alias)]\\n:::"},{"id":"/explorations/chyn/chyn","metadata":{"permalink":"/tech/explorations/chyn/chyn","source":"@site/work/explorations/chyn/chyn.md","title":"CHYN - Revolutionizing Curated Travel with Cloud Computing","description":"--\x3e","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Explorations","permalink":"/tech/tags/explorations"}],"readingTime":2.75,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"CHYN - Revolutionizing Curated Travel with Cloud Computing","tags":["explorations"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/chyn.png"},"unlisted":false,"prevItem":{"title":"Mentoring","permalink":"/tech/local-community-support/mentorships"},"nextItem":{"title":"Paper - Vehicle Collision Prediction Using CNN","permalink":"/tech/explorations/vehicle-collision-prediction/vehicle-collision-prediction"}},"content":"\x3c!-- ## Revolutionizing Curated Travel with Cloud Computing --\x3e\\n\\n\x3c!-- **Team**: Tanya Jain <br /> --\x3e\\n\x3c!-- **Presentation**: Cloud Computing --\x3e\\n\\n## Project Description\\nCHYN, derived from the Hindi word \u091a\u092f\u0928 (chayan), meaning \'to select\' or \'curate\', is a cloud-based platform designed to make curated travel more accessible. Utilizing advanced Machine Learning (ML) technologies, CHYN fills significant gaps in the oversaturated travel market, focusing on providing a highly personalized and accessible daily travel experience.\\n\\n<div className=\\"image-display\\"> \\n![chyn Set Up Journey](./images/chyn_setup.png)\\n</div>\\n\\n## Motivation\\nThe project was inspired by the need to streamline the curated travel experience, making it more accessible and tailored through the use of cutting-edge ML technologies. CHYN aims to simplify the process of travel planning by automating the curation based on individual preferences and insights derived from vast amounts of travel data.\\n\\n## System Architecture\\nCHYN leverages a robust cloud-based architecture to deliver its services:\\n\\n- **Frontend**: Utilizes React (switched from Vue3 for better static file generation).\\n- **Hosting**: AWS S3 bucket hosts the SPA, enabling web app hosting with automated builds and deployments via GitHub Actions.\\n- **Security and Access**: Managed through AWS Route 53 for DNS resolution, AWS CloudFront for content delivery, and SSL certificates for secure user access.\\n- **Authentication**: AWS Cognito is used for secure user authentication and authorization with JWT tokens.\\n- **Backend Processing**: AWS Lambda functions handle CRUD operations, integrated with AWS RDS for relational data storage.\\n\\n<div className=\\"image-display\\"> \\n![chyn Architecture](./images/chyn_architecture.png)\\n</div>\\n\\n## Key Technologies and Innovations\\n- **AWS Polly**: Enhances accessibility by converting text to audio, aiding travelers who prefer audio guides or are visually impaired.\\n- **AWS Bedrock x Claude**: Employs LLM models to extract noteworthy places and details from textual content, making it easier for users to bookmark places from blogs and articles.\\n\\n## Challenges\\n- Managing S3 bucket configurations and ensuring that bucket names match the desired domain names.\\n- Handling AWS Security Token Service (STS) for secure role assumption by IAM users.\\n- Addressing common issues like 404 NotFound errors for misconfigured endpoints.\\n\\n## Impact and Significance\\nCHYN significantly impacts the travel industry by providing a platform that not only simplifies the travel planning process but also enhances the accessibility and personalization of travel experiences. It addresses key challenges in curated travel, such as the need for personalized recommendations and the ability to seamlessly integrate travel insights and preferences.\\n\\n## Limitations\\n- The application currently operates with a limited scope, primarily focusing on San Francisco.\\n- Privacy considerations prevent the use of background tracking, limiting real-time data gathering.\\n- Distances between locations are calculated as the crow flies, which may not always reflect actual travel distances.\\n\\n## Conclusion\\nCHYN has successfully demonstrated how a range of AWS services can be integrated to build a comprehensive cloud-based solution for the travel industry. The project underscores the importance of security in cloud deployments and highlights the potential for cloud technologies to significantly enhance user experiences in web applications.\\n\\n## Future Scope\\n- **Personalized Recommendations**: Introduce algorithms that tailor travel recommendations based on user behavior and past itineraries.\\n- **Social Sharing**: Develop features that allow users to share their travel plans with friends or on social media platforms.\\n- **Surprise Me Feature**: Implement an innovative feature that generates random but intriguing travel plans for users seeking spontaneous travel experiences."},{"id":"/explorations/vehicle-collision-prediction/vehicle-collision-prediction","metadata":{"permalink":"/tech/explorations/vehicle-collision-prediction/vehicle-collision-prediction","source":"@site/work/explorations/vehicle-collision-prediction/vehicle-collision-prediction.md","title":"Paper - Vehicle Collision Prediction Using CNN","description":"Project Overview","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Explorations","permalink":"/tech/tags/explorations"}],"readingTime":2.64,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Paper - Vehicle Collision Prediction Using CNN","tags":["explorations"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/vcp-cover.png"},"unlisted":false,"prevItem":{"title":"CHYN - Revolutionizing Curated Travel with Cloud Computing","permalink":"/tech/explorations/chyn/chyn"},"nextItem":{"title":"Open GIS Project - Making Data Accessible","permalink":"/tech/local-community-support/gis/gis"}},"content":"## Project Overview\\nThis project explores groundbreaking advancements in vehicle collision prediction algorithms using convolutional neural networks (CNNs). Highly recognized among the top 20% of submissions at the ICDAM international conference, our research presents a comprehensive analysis of 108 CNN configurations, significantly enhancing autonomous vehicle safety by innovatively addressing real-world complexities.\\n\\n<div className=\\"image-display\\"> \\n![Vehicle Collision Prediction](./images/vcp-cover.png)\\n</div>\\n\\n## Objectives\\n### Develop a Highly Accurate System\\nCreate a system that predicts vehicle collisions with high accuracy andminimal computational resources. This system aims to improve the reliability and responsiveness of autonomous vehicles in real-world conditions, ultimately enhancing road safety.\\n\\n### Evaluation\\nAssess various CNN configurations on performance metrics such as accuracy, precision, recall, and F1-score. The goal is to identify optimal configurations that ensure the best balance between performance and computational efficiency, facilitating widespread adoption in the automotive industry.\\n\\n## Methodology\\n\\nThe study involved creating and analyzing a substantial dataset of 8,284 data points and detailing the performance of various CNN configurations, examining aspects like accuracy, precision, recall, and F1-score. The detailed comparative analysis of various configurations -- including different layers, activation functions, optimizers, and loss functions, provides valuable insights into which combinations of techniques and optimizations yield the best results.\\n\\n![CNN Model](./images/vcp-cnn.png)\\n\\n## Key Findings\\n\\nThe top-performing CNN configuration achieved 100% accuracy along with perfect precision, recall, and F1-score, demonstrating its capability to reliably predict vehicle collisions in complex environments.\\n\\nThis high accuracy, coupled with low computational demands, marks a significant step forward in making advanced autonomous driving technologies more practical and accessible.\\n\\n## Key Challenges\\n\\n### Data Limitations\\nSignificant challenges arose from the restricted availability and variability of real-world collision data, which is crucial for training predictive models.\\n\\n### Complexity in Prediction \\nObject prediction in autonomous driving typically benefits from the recognizable and consistent structures of objects like cars and humans. However, collision scenarios often partially or completely deform these structures, complicating the prediction process. This deformation disrupts the basic geometric and visual cues that are essential for accurate recognition, presenting a unique and significant challenge for collision prediction systems.\\n\\n### System Efficiency\\nAchieving high accuracy in collision prediction while maintaining computational efficiency was paramount, given the real-time operational needs of autonomous vehicles. This balance is crucial for the practical deployment of AI in dynamic environments, where both speed and reliability are critical.\\n\\n![Vehicle Collision Prediction](./images/vcp-prediction.png)\\n\\n## Impact\\nThis research substantially advances the field of collision prediction algorithms, with significant implications for enhancing public safety and the operational efficiency of autonomous transportation systems. By improving the accuracy and reliability of such predictions, the technology can drastically reduce the incidence of road accidents, thereby saving lives and minimizing injuries.\\n\\n## Future Work\\nThe next phase will focus on integrating and testing these CNN configurations in real-world scenarios with diverse types of autonomous vehicles. This effort will aim to further refine the models to handle a variety of traffic conditions, improving the overall robustness and reliability of the collision prediction technologies.\\n\\n## Conclusion\\nBy setting new benchmarks in vehicle safety through innovative AI techniques, this project makes crucial contributions to enhancing global road safety. The distinguished recognition of our paper underscores the transformative impact and pioneering nature of our research."},{"id":"/local-community-support/gis/gis","metadata":{"permalink":"/tech/local-community-support/gis/gis","source":"@site/work/local-community-support/gis/gis.md","title":"Open GIS Project - Making Data Accessible","description":"Real-Time GIS Framework for Yamuna\'s Environmental Monitoring","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":2.275,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Open GIS Project - Making Data Accessible","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/gis/gui_1.jpg"},"unlisted":false,"prevItem":{"title":"Paper - Vehicle Collision Prediction Using CNN","permalink":"/tech/explorations/vehicle-collision-prediction/vehicle-collision-prediction"},"nextItem":{"title":"3. Reclaiming the Fertility Journey","permalink":"/tech/local-community-support/rita-ai/rita-ai"}},"content":"## Real-Time GIS Framework for Yamuna\'s Environmental Monitoring\\n**Institution**: Amity University, Noida, India <br />\\n**Advisor**: Madhuri Kumari, Nitasha Hasteer\\n\\n![GIS GUI Image](./images/gui_1.jpg)\\n\\n## Project Description\\nEnvironmental policy suffers when data remains inaccessible to convey its own problems. Under [Dr. Madhuri Kumari]\u2019s guidance, I teamed up with [ALiAS] members and developed a GIS-based web framework for real-time river pollution monitoring\u2014built on open-source tools to ensure transparency and adaptability.\\n\\nThe platform delivers critical data to stakeholders across the Government of India, equipping environmental researchers with the evidentiary foundation needed to advocate for policy reform. The same ethos that guided ALiAS\u2014open knowledge, accessible infrastructure\u2014applies as urgently to river systems as to codebases.\\n\\n[ALiAS]: ../../../writings/alias\\n[Dr. Madhuri Kumari]: https://scholar.google.co.in/citations?user=Salw3OoAAAAJ&hl=en\\n\\n## Overview\\n\\nDeveloped a robust web-based Geographic Information System (GIS) leveraging open-source technologies to monitor environmental phenomena, such as river pollution levels. The solution integrates spatial data management across various geographic locations, providing a scalable and intuitive tool for environmental researchers and decision-makers.\\n\\n![GIS Framework Diagram](./images/gis_framework.jpg)\\n\\n## Objectives\\n - Facilitate the real-time visualization and management of environmental data.\\n - Employ cost-effective, open-source tools to ensure wide accessibility and adaptability.\\n\\n## Comprehensive Technology Stack\\n - **Frontend**: HTML, CSS, JavaScript, AJAX, jQuery, Bootstrap\\n - **Backend**: Django, used for handling API requests, data management, and server-side logic.\\n - **Database**: PostgreSQL, for secure and scalable data storage.\\n - **GIS Tools**: QGIS, SAGA GIS for spatial data analysis and management.\\n - **Data Analysis and Visualization**: Pandas for data handling and manipulation, Google Charts for creating dynamic, interactive graphical representations of data.\\n\\n## System Architecture\\nThe architecture is structured into three layers:\\n\\n - **Client Layer**: Employs AJAX and jQuery for responsive user interactions and real-time data updates.\\n - **Application Layer**: Django serves as the backbone, managing authentication, database interactions, and API integrations.\\n - **Database Layer**: Utilizes PostgreSQL to manage both spatial and non-spatial data efficiently.\\n\\n<div className=\\"max-w-400px\\"> \\n![Application Layer Diagram](./images/gis_application_layer.jpg)\\n</div>\\n\\n## Key Features and Innovations\\n - **Dynamic Data Visualization**: Interactive maps and graphs allow for comprehensive analysis and reporting of environmental data.\\n - **Advanced Data Management**: Supports multiple data formats and facilitates seamless data input and manipulation through a well-designed GUI.\\n - **Enhanced User Experience**: Features such as map zooming, shapefile overlaying, and real-time filtering enhance user interaction and data accessibility.\\n\\n![GIS GUI Image](./images/gui_2.png)\\n\\n## Impact and Significance\\nThis project supports critical environmental initiatives, such as the monitoring and management of river pollution. By leveraging advanced GIS capabilities and open-source technologies, the framework aids in making informed decisions that significantly impact community health and environmental preservation.\\n\\n## Conclusion\\nThis GIS framework demonstrates the power of integrating open-source technology with advanced data analysis tools to address environmental challenges. It is a pivotal solution for researchers and policymakers aiming to enhance environmental monitoring and decision-making processes."},{"id":"/local-community-support/rita-ai/rita-ai","metadata":{"permalink":"/tech/local-community-support/rita-ai/rita-ai","source":"@site/work/local-community-support/rita-ai/rita-ai.mdx","title":"3. Reclaiming the Fertility Journey","description":"Rita Pod AI","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Local Community Support","permalink":"/tech/tags/local-community-support"}],"readingTime":0.7,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"3. Reclaiming the Fertility Journey","tags":["local-community-support"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/rita-ai/rita-pod.png"},"unlisted":false,"prevItem":{"title":"Open GIS Project - Making Data Accessible","permalink":"/tech/local-community-support/gis/gis"},"nextItem":{"title":"ALiAS - Amity Linux Assistance Sapience","permalink":"/tech/open-source/alias/alias"}},"content":"![Rita Pod AI](./images/rita-pod.png)\\n\\n## Rita pod AI\\n\\nFertility care is often isolating and a driving question to solve this issue was - how might we make an inherently isolating process feel communal? At the [South Park Commons] Hackathon, sponsored by [OpenAI], I collaborated with [Kamily Staryga] (CEO, Rita Health) and [Simran Kaur] (ex-Meta PM) to construct an alternative - Rita Pod, a platform that reframes fertility support as a community-driven experience.\\n\\nWe fused AI with medically validated assessments to connect women in need of care to navigate similar stages. To address the loneliness and confusion that permeate fertility journeys, it featured real-time misinformation correction, voice input, emotional recognition, and personalized peer support.\\n\\n<video src={require(\'./images/rita-pod.mp4\').default} width=\\"560\\" height=\\"315\\" controls></video>\\n\\n[Loom] | [Rita AI Website]\\n\\n[Kamily Staryga]: https://www.linkedin.com/in/kamilastaryga\\n[Simran Kaur]: https://www.linkedin.com/in/kaur-simran\\n[South Park Commons]: https://www.southparkcommons.com/\\n[OpenAI]: https://openai.com/\\n\\n[Loom]: https://www.loom.com/share/5a758a8baedc40ecac15e538d00bc3dc?sid=121b4f59-d01b-4a19-a7a3-158989c36a60\\n[Rita AI Website]: https://www.wearerita.com/"},{"id":"/open-source/alias/alias","metadata":{"permalink":"/tech/open-source/alias/alias","source":"@site/work/open-source/alias/alias.mdx","title":"ALiAS - Amity Linux Assistance Sapience","description":"ALiAS - Amity Linux Assistance Sapience","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Open Source Software","permalink":"/tech/tags/oss"}],"readingTime":0.595,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"ALiAS - Amity Linux Assistance Sapience","tags":["oss"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"3. Reclaiming the Fertility Journey","permalink":"/tech/local-community-support/rita-ai/rita-ai"},"nextItem":{"title":"Arrow Air","permalink":"/tech/open-source/arrowair/arrow-air"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n## ALiAS - Amity Linux Assistance Sapience\\n\\n<OrganisationBlock \\n    name=\\"ALiAS\\"\\n    logoLight=\\"https://avatars.githubusercontent.com/u/20925586?s=280&v=4\\"\\n    logoDark=\\"https://avatars.githubusercontent.com/u/20925586?s=280&v=4\\"\\n    description=\\"[ALiAS](https://asetalias.in/) is a student-led organization cum tech community that fosters open-source culture, the use of Linux and the culture of hacking and sharing.\\"\\n    socials={[\\n        { name: \'GitHub\', link: \'https://github.com/asetalias\' },\\n        { name: \'Website\', link: \'https://asetalias.in/\' },\\n        { name: \'LinkTree\', link: \'https://linktr.ee/asetalias\' },\\n        { name: \'Twitter\', link: \'https://twitter.com/asetalias\' },\\n        { name: \'LinkedIn\', link: \'https://www.linkedin.com/company/asetalias/\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nAs a repository maintainer, I contributed to website development, documentation, and the creation of logistical systems for administrative and event management. I also assisted with social media strategy and developed a mobile application in Summer 2018.\\n\\n:::note[[Read more about my journey with ALiAS](../../../writings/alias)]\\n:::"},{"id":"/open-source/arrowair/arrow-air","metadata":{"permalink":"/tech/open-source/arrowair/arrow-air","source":"@site/work/open-source/arrowair/arrow-air.mdx","title":"Arrow Air","description":"About the organisation","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Open Source Software","permalink":"/tech/tags/oss"}],"readingTime":0.825,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"Arrow Air","tags":["oss"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/arrow-air.png"},"unlisted":false,"prevItem":{"title":"ALiAS - Amity Linux Assistance Sapience","permalink":"/tech/open-source/alias/alias"},"nextItem":{"title":"LinuxChix India","permalink":"/tech/open-source/linux-chix/linux-chix"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n\\n#### About the organisation\\n\\n<OrganisationBlock \\n    name=\\"Arrow Air\\"\\n    logoLight=\\"\\"\\n    logoDark=\\"https://assets-global.website-files.com/639a2d8db0ff26e6ca7a68ff/639b4d564b6eae570db90e0b_arr_logo-nav.svg\\"\\n    description=\\"[Arrow Air](https://www.arrowair.com/) DAO is a decentralized community building vertical-takeoff and landing vehicles (VTOLs) along with the services and infrastructure to transport people and goods. The open source AAM ecosystem for flight planning and VTOL asset management is now an independent organisation named [aetheric](https://www.aetheric.nl/), based in Netherlands.\\"\\n    socials={[\\n        { name: \'Website\', link: \'https://www.arrowair.com/\' },\\n        { name: \'GitHub\', link: \'https://github.com/Arrow-air\' },\\n        { name: \'LinkedIn\', link: \'https://www.linkedin.com/company/arrowair\' },\\n    ]}\\n/>\\n\\n#### The work\\n\\n**The Mission**: To revolutionize the user experience for VTOL logistics by building an intelligent,\\nAI-native platform from the ground up.\\n\\n**My Strategy**: Led full-stack development, architecting a Gen AI-powered web app with a React frontend\\n and a Python backend featuring a RAG pipeline (OpenAI, Pinecone).\\n\\n**The Results**: Engineered the full stack web app, for accurate, real-time intelligence. Delivered a high \\nperformance app with sub-1.5s FCP and enhanced user personalisation and operational efficiency by shipping \\na core AI feature.\\n\\n![Web App](./arrow-air.png)"},{"id":"/open-source/linux-chix/linux-chix","metadata":{"permalink":"/tech/open-source/linux-chix/linux-chix","source":"@site/work/open-source/linux-chix/linux-chix.mdx","title":"LinuxChix India","description":"LinuxChix India","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Open Source Software","permalink":"/tech/tags/oss"}],"readingTime":0.5,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"LinuxChix India","tags":["oss"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z","type":"project","cover_image":"/img/work/linux-chix/linuxchix-india-cover.png"},"unlisted":false,"prevItem":{"title":"Arrow Air","permalink":"/tech/open-source/arrowair/arrow-air"},"nextItem":{"title":"pandas-dev","permalink":"/tech/open-source/pandas/pandas"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n## LinuxChix India\\n\\n#### About the organisation\\n\\n<OrganisationBlock\\n    name=\\"LinuxChix India\\"\\n    logoLight=\\"https://avatars.githubusercontent.com/u/24838409?s=280&v=4\\"\\n    logoDark=\\"https://avatars.githubusercontent.com/u/24838409?s=280&v=4\\"\\n    description=\\"[LinuxChix India](http://india.linuxchix.org/) is a non-profit organization for the Linux user groups in India, passionate about sharing knowledge and learning. It aims to promote gender diversity in Free and Open Source Software (FOSS) communities in India.\\"\\n    socials={[\\n        { name: \'GitHub\', link: \'https://github.com/linuxchixin\' },\\n        { name: \'Website\', link: \'http://india.linuxchix.org/\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nI developed the website from the ground up as part of a redesign initiative, optimizing all pages for mobile responsiveness and accessibility.\\n\\n<div className=\\"image-display image-80-perc\\"> \\n![LinuxChix India website UI](./linuxchix-india-cover.png)\\n</div>"},{"id":"/open-source/pandas/pandas","metadata":{"permalink":"/tech/open-source/pandas/pandas","source":"@site/work/open-source/pandas/pandas.mdx","title":"pandas-dev","description":"Pandas","date":"2024-05-15T00:00:00.000Z","tags":[{"inline":false,"label":"Open Source Software","permalink":"/tech/tags/oss"}],"readingTime":0.48,"hasTruncateMarker":false,"authors":[{"name":"Tanya Jain","title":"Author","url":"https://github.com/tanyaacjain","socials":{"x":"tanyaacjain","github":"tanyaacjain"},"imageURL":"https://github.com/tanyaacjain.png","key":"tanya"}],"frontMatter":{"title":"pandas-dev","tags":["oss"],"authors":"tanya","date":"2024-05-15T00:00:00.000Z"},"unlisted":false,"prevItem":{"title":"LinuxChix India","permalink":"/tech/open-source/linux-chix/linux-chix"}},"content":"import { OrganisationBlock } from \'@sawatdeehaneu/docusaurus-theme\';\\n\\n## Pandas\\n\\n#### About the organisation\\n\\n<OrganisationBlock\\n    name=\\"Pandas\\"\\n    logoLight=\\"https://upload.wikimedia.org/wikipedia/commons/thumb/e/ed/Pandas_logo.svg/1280px-Pandas_logo.svg.png\\"\\n    logoDark=\\"\\"\\n    description=\\"[Pandas](https://pandas.pydata.org/) is a software library written for the Python programming language for data manipulation and analysis. It is designed to handle the dirty work of data preparation and transformation that is often required before statistical analysis can be performed.\\n    \\\\\\n    Used by 1.7M repositories. 42.2K stars.\\"\\n    socials={[\\n        { name: \'GitHub\', link: \'https://github.com/pandas-dev\' },\\n        { name: \'Website\', link: \'https://pandas.pydata.org/\' },\\n    ]}\\n/>\\n\\n#### Contribution\\n\\nI enhanced documentation and conducted data analysis to improve the tool\'s accessibility for a global developer audience."}]}}')}}]);